class ArrayStack(Stack):

   def __init__(self):
       self._data = []

   def push(self, item):
       self._data.append(item)

   def pop(self):
       return self._data.pop()

   def is_empty(self):
       return len(self._data) == 0

   def peek(self):
       if self.is_empty():
           raise Empty('Stack is empty')
       return self._data[-1]

   def size(self):
       return len(self._data)

